### Create a ChatKit session.
# @name CreateChatSessionMethod
POST {{host}}/chatkit/sessions
Authorization: Bearer {{token}}
Content-Type: application/json
Accept: application/json

{
  "workflow": {
    "id": "string",
    "version": "string",
    "state_variables": {},
    "tracing": {
      "enabled": true
    }
  },
  "user": "string",
  "expires_after": {
    "anchor": "created_at",
    "seconds": 0
  },
  "rate_limits": {
    "max_requests_per_1_minute": 0
  },
  "chatkit_configuration": {
    "automatic_thread_titling": {
      "enabled": true
    },
    "file_upload": {
      "enabled": true,
      "max_file_size": 0,
      "max_files": 0
    },
    "history": {
      "enabled": true,
      "recent_threads": 0
    }
  }
}

## Responses
# 200
# Description: Success
# Content-Type: application/json

using var client = new OpenAiClient(apiKey);

var request = global::System.Text.Json.JsonSerializer.Deserialize<global::tryAGI.OpenAI.CreateImageEditRequest>(
    @"{
  ""model"": ""gpt-image-1.5"",
  ""prompt"": ""Replace the background with a snowy mountain scene"",
  ""images"": [
    {
      ""file_id"": ""file-abc123""
    }
  ],
  ""mask"": {
    ""file_id"": ""file-mask123""
  },
  ""output_format"": ""png"",
  ""output_compression"": 100
}")!;

var response = await client.Images.CreateImageEditAsync(
